SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_atm_dep_creditor ON sc_atm_dep_creditor CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_atm_dep_creditor() RETURNS trigger AS $BODY$
BEGIN
  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_atm_dep_creditor
    where deposit_account_no = NEW.deposit_account_no;
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;
  if coalesce(trim(both NEW.NEW_SEND_STATUS)::text, '') = '' then NEW.NEW_SEND_STATUS := '0';end if;

  --Niorn 2023-07-10 JUN ปรับขนาด bank_code
  if trim(both NEW.bank_code) = '06'  then NEW.bank_code := '006';end if;
  if trim(both NEW.bank_code) = '25' then NEW.bank_code := '025';end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_atm_dep_creditor() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_atm_dep_creditor
	BEFORE INSERT OR UPDATE ON sc_atm_dep_creditor FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_atm_dep_creditor();

